var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"무슨 얘기들을 하는 거야!","JPN":"何言ってるんだよ！","ENG":"Do you even hear yourselves?!","TWN":"你們在說什麼！"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"당장 일어나! 빨리 도망쳐야 된다고!","JPN":"今すぐ起きろ！　早く逃げないと！","ENG":"Get up! We’re getting you out of here!","TWN":"快起來！趕快逃離這裡！"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RUNAWAY_NPC_OZ_NAME","text":{"KOREA":"너야 말로 이상한 소리 좀…… 그만해…….","JPN":"あんたこそ変なこと……言わないでよ……","ENG":"Same goes for you... Stop talking nonsense...","TWN":"你好奇怪喔……不要再說這些有的沒的……"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"지나! 전에 도망쳤었잖아! 기억 안나?","JPN":"ジナ！　前に逃げてただろ？　覚えてない？","ENG":"Gina! You ran away before, remember?","TWN":"吉娜！你忘了嗎？你之前不是也逃跑過！"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RUNAWAY_NPC_OZ_NAME","text":{"KOREA":"그랬지……. 정말 바보 같은 일이었어…….","JPN":"そうだったね……本当にバカだった……","ENG":"I did... It was such a stupid thing to do...","TWN":"對啊……真是有夠愚蠢的……"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"뭐?","JPN":"は？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RUNAWAY_NPC_OZ_NAME","text":{"KOREA":"왜 그랬을까……? 뭐…… 질풍노도의 시기니까 잠깐 방황할 수도…… 있지.","JPN":"なんでそんなことしたんだろう……？　まあ……疾風怒濤の時代なんだから彷徨うことだって……あるよね。","ENG":"What was I thinking? Maybe... I was going through a storm and stress period, you know?","TWN":"我幹嘛要逃呢……？可能是……一時迷失……吧？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RUNAWAY_NPC_OZ_NAME","text":{"KOREA":"덕분에 벌은 실컷 받았고…… 대신 헤론 님께서 날 <color=#ffd34c>헤이븐 랜드</color>에 취직시켜주신다고…… 했어.","JPN":"おかげでいっぱいお仕置きされたし……その代わり、ヘロン様が私を<color=#ffd34c>ヘイブンランド</color>で働けるようにしてくれるって……言ったんだ。","ENG":"I got punished a lot because of that... But Madam Heron also said she'd let me work at <color=#ffd34c>Havenland</color>...","TWN":"幸虧你把我抓回來，雖然有受到嚴厲的懲罰……但是海倫夫人說要安排我到<color=#ffd34c>天堂樂園</color>……工作。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RUNAWAY_NPC_OZ_NAME","text":{"KOREA":"그곳에서는 놀면서 일할 수 있대……. 그게 바로 천국이지. 안 그래?","JPN":"あそこでは遊びながら仕事もできるんだって……まさに天国だよ。そうじゃない？","ENG":"She said I could work there while playing... Isn’t that paradise?","TWN":"夫人說那裡可以一邊玩樂一邊工作……簡直就是真正的天堂，你說是不是？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"부러워……. 나도 빨리 졸업했으면…… 좋겠다.","JPN":"羨ましい……私も早く……卒業したい。","ENG":"I’m so jealous... I wish I could graduate here soon...","TWN":"好羨慕喔……我也想……趕快畢業。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RUNAWAY_NPC_OZ_NAME","text":{"KOREA":"그곳으로 갈 수 있게 됐는데…… 내가 뭐하러 도망을 가……?","JPN":"そこに行けるようになったのに……なんで逃げるの……？","ENG":"I’ve finally made it... So why would I want to run away...?","TWN":"我現在可以去那麼棒的地方……幹嘛還要逃……？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RUNAWAY_NPC_OZ_NAME","text":{"KOREA":"어차피…… 도망쳐도 잡혀서 벌이나…… 받을 게 뻔한데…….","JPN":"どうせ……逃げても捕まって、お仕置き……されるのに……","ENG":"Besides... Even if I run away... I’ll just get caught and receive punishment again...","TWN":"更何況……就算逃跑也一定會被抓回來……還要受罰……"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"지나…….","JPN":"ジナ……","ENG":"Gina...","TWN":"吉娜……"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RUNAWAY_NPC_OZ_NAME","text":{"KOREA":"너희는 배신자야. 헤론 님께서 배신자는 용서하지 말라고 하셨어.","JPN":"あんたたちは裏切り者よ。ヘロン様が裏切り者は許すなって言ってた。","ENG":"You’re all traitors. And Madam Heron said to never forgive betrayers like you.","TWN":"你們是叛徒，海倫夫人說叛徒是不可原諒的。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"맞아. 잡아서 바치자.","JPN":"そうだよ。捕まえて捧げよう。","ENG":"Right. We should turn you in.","TWN":"沒錯，把她們抓起來交給海倫夫人。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"묶어두고 얌전히 기다리면 헤론 님께서 칭찬해 주실 거야.","JPN":"縛っておいて大人しく待ってれば、ヘロン様が褒めてくれる。","ENG":"If we tie them up and wait patiently for Madam Heron, I’m sure she’ll praise us.","TWN":"把他們綁起來，等海倫夫人來看到一定會獎勵我們的。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RUNAWAY_NPC_OZ_NAME","text":{"KOREA":"잡아. 더 이상 도망치지 못하게.","JPN":"捕まえろ。二度と逃げられないように。","ENG":"Get them. Don’t let them run away.","TWN":"抓起來，不能讓她們又逃掉。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"너희들…….","JPN":"みんな……","ENG":"You guys...","TWN":"你們……"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};